+	console.log('');
+	console.log('Copy the following into vscode-distro\'s `product.json` under the top-level `agentSdks` key:');
+	console.log('');
+	console.log('```json');
+	console.log(JSON.stringify({ agentSdks: fragment }, null, 2));
+	console.log('```');
